import SwiftUIstruct EventButton: View {    let title: String    let icon: String    let isLogged: Bool    let action: () -> Void        var body: some View {        Button(action: action) {            HStack {                Image(systemName: icon)                    .font(.title2)                Text(title)                    .font(.title3)                    .fontWeight(.semibold)                Spacer()                if isLogged {                    Image(systemName: "checkmark.circle.fill")                        .foregroundStyle(.green)                        .font(.title3)                }            }            .padding()            .frame(maxWidth: .infinity)            .background(isLogged ? Color.green.opacity(0.2) : Color.purpleAccent.opacity(0.2))            .foregroundStyle(isLogged ? .green : .primary)            .clipShape(RoundedRectangle(cornerRadius: 16))        }        .padding(.horizontal)        .disabled(isLogged)    }}